import{_ as t,o as e,c as r,a3 as o}from"./chunks/framework.CVjg771q.js";const g=JSON.parse('{"title":"天干地支的由来","description":"从木星观测到斗建体系——天干地支的天文学起源","frontmatter":{"pageClass":"dao-changshi-page","aside":false,"title":"天干地支的由来","description":"从木星观测到斗建体系——天干地支的天文学起源"},"headers":[],"relativePath":"changshi/tiangan-dizhi/you-lai.md","filePath":"changshi/tiangan-dizhi/you-lai.md","lastUpdated":1779783531000}'),i={name:"changshi/tiangan-dizhi/you-lai.md"};function n(s,a,l,h,p,d){return e(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="天干地支的由来" tabindex="-1">天干地支的由来 <a class="header-anchor" href="#天干地支的由来" aria-label="Permalink to &quot;天干地支的由来&quot;">​</a></h1><blockquote><p>参考：知乎 <a href="https://www.zhihu.com/question/1799468214/answer/1987558251991160331" target="_blank" rel="noreferrer">懿文君</a></p></blockquote><h2 id="木星与太岁" tabindex="-1">木星与太岁 <a class="header-anchor" href="#木星与太岁" aria-label="Permalink to &quot;木星与太岁&quot;">​</a></h2><p>木星即太岁。「太」是尊称，是对木星作为岁星的尊称。</p><p>关于岁星纪年，一个常见的误解是：木星周期 11.86 年，所以古人用着用着就不准了，于是造了个假想天体「太岁」来凑合。事实并非如此。</p><p>11.86 年是木星的<strong>恒星周期</strong>，并非以地球为参考点的旋转周期。以地球为不动参考点，木日会和周期为 398.88 天，木星每 398.88 天围绕地球移动约 33.15°。11 个木日会和周期后（约 12.0128 年后），木星回到原点。这套历法已用了近三千年而未出现误差，可见古人的观测精度之高。</p><h2 id="斗建体系" tabindex="-1">斗建体系 <a class="header-anchor" href="#斗建体系" aria-label="Permalink to &quot;斗建体系&quot;">​</a></h2><p>古人仰望北方星空，发现中天的星星围绕一个中心做圆周运动。以<strong>北斗星</strong>为观察对象最为直观：</p><ul><li>每天固定时间（如子时）观察北斗位置，每天逆时针移动一度，<strong>一年刚好一周</strong>（地球公转 + 自转）</li><li>整晚连续观察，会发现北斗逆时针转动，<strong>一天一周</strong>（地球自转）</li></ul><p>基于北斗与木星的旋转规律，诞生了<strong>斗建太岁</strong>体系——</p><ul><li>以天心为圆心画圆，平均划分十二等份</li><li>于是：1 纪 = 12 岁，1 岁 = 12 月，1 日 = 12 时辰</li></ul><h2 id="方向之争的由来" tabindex="-1">方向之争的由来 <a class="header-anchor" href="#方向之争的由来" aria-label="Permalink to &quot;方向之争的由来&quot;">​</a></h2><p>北斗观测是面向北斗方向，恒星从北向东移动是<strong>逆时针</strong>的，落到纸面上就是：上南下北，左西右东。</p><p>二十八宿体系则是观测者转了个身（面向南方），恒星移动变成<strong>顺时针</strong>，落到纸面上：上南下北，左东右西（东西对调）。</p><p>再加上后来的「乾坤倒置」「早晚子时之争」等历史问题，导致十二星次、十二地支、十二岁的对应关系在纸面上变得复杂。</p><h2 id="从岁星到甲子" tabindex="-1">从岁星到甲子 <a class="header-anchor" href="#从岁星到甲子" aria-label="Permalink to &quot;从岁星到甲子&quot;">​</a></h2><p>古人后来将十二年一轮的岁星纪年<strong>升级为六十年一轮的甲子纪年</strong>。六十花甲子成为新的纪年法并一直沿用至今。再后来，六十花甲子渐渐神格化、人格化为六十位太岁神，衍生出一套祈福攘灾的仪式。</p>',17)])])}const u=t(i,[["render",n]]);export{g as __pageData,u as default};
